import React, { useEffect } from 'react';
import { Link } from "react-router-dom";
import JsBarcode from 'jsbarcode';

function Card({cardobj}) {
  const cardData = cardobj.cardobj; // somehow gained an extra level on top of cardobj with another carobj
  
  const cardId = cardData.nameref + cardData.id;
  const cardRef = "#" + cardId; // added hash #
  useEffect(() => {
    //setTimeout(()=>{
    if (cardData.generatebarcode === true) {
      JsBarcode(cardRef, cardData.barcode, {format: "ean13"});
    }
    //}, 2000);
  }, []); // <-- empty array means 'run once'

  return (
    <div>
      <div className="card">
        <div className="card-name">{cardData.name}</div>
          {cardData.generatebarcode && <div className="card-barcode"><svg id={cardId}></svg></div>}
          {!cardData.generatebarcode && <div className="card-barcode"><img src={cardData.barcode} alt={cardData.name} /></div>}
      </div>
      <div class="card-back-button simple-button-style">
        <Link to="/">
          Terug
        </Link>
      </div>
    </div>
  );
};

export default Card;