import React, { useState } from 'react';
import Parse from 'parse/dist/parse.min.js';

function AddCard({newCardName, newBarCode, newImgUrl}) {
  // State variables
  const [card, setCard] = useState({});

  async function addCard() {
    try {
      // create a new Parse Object instance
      const Card = new Parse.Object('Card');
      // define the attributes you want for your Object
      Card.set('name', card.name);
      Card.set('barcode', card.barcode); // 2621837375437
      Card.set('imgurl', card.imgurl); // https://upload.wikimedia.org/wikipedia/en/6/62/Etos_logo.svg
      // save it on Back4App Data Store
      await Card.save();
      console.log('Card saved!');
    } catch (error) {
      console.log('Error saving new card: ', error);
    }
  }
  const handleCardData = (event) => {
    const name = event.target.name;
    const value = event.target.value;
    setCard(values => ({...values, [name]: value}))
  }
  return (
    <div>
      <input type="text" id="cardName" name="name" onChange={handleCardData} value={card.name || ""} />
      <input type="text" id="barCode" name="barcode" onChange={handleCardData} value={card.barcode || ""} />
      <input type="text" id="imgUrl" name="imgurl" onChange={handleCardData} value={card.imgurl || ""} /> 
      <button onClick={addCard}>Add Card</button>
    </div>
  );
};

export default AddCard;