import { Link } from "react-router-dom";

function CardThumbnail({cardobj}) {
  return (
    <div className="card-thumbnail">
      <Link to="/details" state={{cardobj: {cardobj}}} >
        <img src={cardobj.imgurl} alt={cardobj.name} />
      </Link>
    </div>
  );
};

export default CardThumbnail;